import { createContext, useContext, useState } from 'react';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);

  // Ginawa nating async para hindi mag-error ang 'await' sa LoginPage
  // At nilagyan natin ng email/password check dito (Temporary Mock Logic)
  const login = async (email, password) => {
    
    // MOCK LOGIN LOGIC: Palitan mo ito ng totoong API call pag ready na backend mo
    if (email === 'admin@example.com' && password === 'password123') {
      const userData = { email, role: 'admin' };
      
      setUser(userData);
      localStorage.setItem('user', JSON.stringify(userData));
      
      return userData; // <--- Eto ang kailangan ng LoginPage mo!
    } else {
      // Kung mali ang credentials, mag-throw ng error para mahuli ng 'catch'
      throw new Error('Invalid email or password');
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
  };

  return (
    <AuthContext.Provider value={{ user, setUser, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
